import 'dart:math' as math;

import 'package:flutter/foundation.dart';

/// Decides when GPU precision is likely insufficient at deep zoom.
///
/// ## Float32 precision analysis
///
/// GPU fragment shaders use float32 arithmetic (~7 significant digits,
/// mantissa ≈ 2^-24 ≈ 6e-8).
///
/// The coordinate span per pixel is: span_per_px = fractal_range / (zoom * resolution)
///   For a 1080p display and a fractal range of ~3 units:
///     span_per_px = 3 / (zoom * 1920) ≈ 1.6e-3 / zoom
///
/// Float32 artifacts appear when the per-pixel span drops below the
/// representable precision at the current center offset. In the worst case
/// (center near origin, no cancellation) this is roughly:
///     artifact threshold zoom ≈ 1.6e-3 / 6e-8 ≈ 2.7e4  ... but only at
///     an offset of ~1.0 unit from origin. Deep in the Mandelbrot boundary
///     where |c| ≈ 2, precision is consumed faster (≈ 1e4–1e5).
///     With the standard center at (0,0) or a well-normalized fractal,
///     artifacts are not visible until zoom ≈ 1e6–1e8.
///
/// Our shaders perform double-width emulation via paired float32 values
/// (see shader uniform layout) for a subset of fractals, extending usable
/// GPU range to ~1e12 before requiring CPU.
///
/// ## Conservative threshold policy
///
/// These thresholds are intentionally HIGH so GPU is used as long as
/// possible. The CPU fallback is a correctness escape hatch, not a
/// performance choice — it is significantly slower and disables GPU effects.
///
/// Raise these thresholds if you observe visible precision artifacts before
/// the switch; lower them only if tested on a low-DPI device where artifacts
/// appear earlier.
@immutable
class DeepZoomPrecisionPolicy {
  /// Maximum iterations we send to GPU shaders for real-time rendering.
  ///
  /// Most escape-time shaders clamp around this value already; keeping the
  /// cap centralized avoids overdriving slower devices at extreme zoom.
  static const int gpuMaxIterations = 2000;

  /// Per-module GPU→CPU fallback thresholds.
  ///
  /// For mandelbrot, the CPU fallback threshold is pushed to [_df2UpperThreshold]
  /// (1e14) because the double-float shader [mandelbrot_df2.frag] covers the
  /// intermediate zoom range [_df2LowerThreshold, _df2UpperThreshold].
  ///
  /// Other escape-time fractals still use float32 GPU up to their threshold,
  /// then fall back to CPU (no df2 variant available yet).
  static const Map<String, double> _cpuFallbackZoomThresholds = {
    // Mandelbrot: df2 shader covers zoom [5e6, 1e12), so CPU fallback only
    // kicks in above 1e12 (the df2 upper bound).
    'mandelbrot': 1e12,
    // Julia & related escape-time fractals: GPU precision degrades sooner,
    // so switch to CPU around ~1e9.
    'julia': 1e9,
    'celtic': 1e9,
    'buffalo': 1e9,
    'burning_ship': 1e9,
    'tricorn': 1e9,
    'multibrot3': 1e9,
    'multibrot4': 1e9,
    'multibrot5': 1e9,
    'phoenix': 1e9,
  };

  /// Default threshold for any fractal type not listed above.
  /// Simple orbit fractals and non-escape-time types lose precision more
  /// slowly; 1e8 is a safe upper bound for float32 at 1080p.
  static const double _defaultThreshold = 1e7;

  /// Zoom range where the double-float (DS) shader [mandelbrot_df2.frag]
  /// should be used instead of the standard float32 shader.
  ///
  /// Below [_df2LowerThreshold]: standard float32 GPU shader is fine.
  /// Between [_df2LowerThreshold] and [_df2UpperThreshold]: DS shader.
  /// Above [_df2UpperThreshold]: CPU fallback required.
  static const double _df2LowerThreshold = 5e6;
  static const double _df2UpperThreshold = 1e12;

  /// Number of consecutive evaluations above the zoom threshold required
  /// before committing to CPU fallback. Prevents rapid GPU↔CPU flicker
  /// when zooming near the boundary.
  static const int _hysteresisFrames = 2;

  const DeepZoomPrecisionPolicy();

  /// Returns true when GPU precision is insufficient at the given zoom.
  ///
  /// Pure, stateless evaluation — callers that want hysteresis should
  /// use [DeepZoomHysteresis] to track frame counts.
  bool shouldUseCpuFallback({
    required String moduleId,
    required double zoom,
  }) {
    final threshold = _cpuFallbackZoomThresholds[moduleId] ?? _defaultThreshold;
    return zoom >= threshold;
  }

  double thresholdFor(String moduleId) =>
      _cpuFallbackZoomThresholds[moduleId] ?? _defaultThreshold;

  /// Returns true when the double-float shader should be used for [moduleId].
  ///
  /// Currently only mandelbrot has a df2 variant. The range is
  /// [_df2LowerThreshold, _df2UpperThreshold] exclusive.
  bool shouldUseDoubleFloat({
    required String moduleId,
    required double zoom,
  }) {
    if (moduleId != 'mandelbrot') return false;
    return zoom >= _df2LowerThreshold && zoom < _df2UpperThreshold;
  }

  int get hysteresisFrames => _hysteresisFrames;

  /// Auto-scales iteration count with zoom depth for GPU rendering.
  ///
  /// Keeps shallow zoom responsive while increasing detail as zoom grows,
  /// reducing under-iteration artifacts in deep zoom.
  ///
  /// Scaling curve:
  /// - zoom <= 1: unchanged
  /// - zoom > 1: base * (1 + 0.35 * log10(zoom))
  /// - clamped to [4, gpuMaxIterations]
  int scaledGpuIterations({
    required int baseIterations,
    required double zoom,
  }) {
    final safeBase = baseIterations.clamp(4, gpuMaxIterations);
    if (zoom <= 1.0) return safeBase;

    final depth = (math.log(zoom) / math.ln10).clamp(0.0, 30.0);
    final factor = 1.0 + 0.35 * depth;
    final scaled = (safeBase * factor).round();
    return scaled.clamp(4, gpuMaxIterations);
  }
}

/// Stateful hysteresis filter for GPU→CPU deep-zoom transitions.
///
/// Wraps [DeepZoomPrecisionPolicy] and requires [policy.hysteresisFrames]
/// consecutive above-threshold evaluations before reporting CPU needed.
/// Drops back to GPU immediately when zoom falls below threshold.
bool _isSameHysteresisStreak({
  required String? previousModuleId,
  required String moduleId,
}) =>
    previousModuleId == moduleId;

class DeepZoomHysteresis {
  final DeepZoomPrecisionPolicy policy;
  String? _trackedModuleId;
  int _aboveThresholdCount = 0;
  bool _cpuActive = false;

  DeepZoomHysteresis({this.policy = const DeepZoomPrecisionPolicy()});

  /// Call this on every zoom change. Returns true if CPU fallback is warranted.
  bool update({required String moduleId, required double zoom}) {
    final overThreshold = policy.shouldUseCpuFallback(
      moduleId: moduleId,
      zoom: zoom,
    );

    if (!_isSameHysteresisStreak(
      previousModuleId: _trackedModuleId,
      moduleId: moduleId,
    )) {
      _aboveThresholdCount = 0;
      _cpuActive = false;
      _trackedModuleId = moduleId;
    }

    if (overThreshold) {
      _aboveThresholdCount++;
      if (_aboveThresholdCount >= policy.hysteresisFrames) {
        _cpuActive = true;
      }
    } else {
      // Immediately drop back to GPU on zoom-out — no delay needed.
      _aboveThresholdCount = 0;
      _cpuActive = false;
    }

    return _cpuActive;
  }

  void reset() {
    _trackedModuleId = null;
    _aboveThresholdCount = 0;
    _cpuActive = false;
  }
}

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/features/renderer/deep_zoom_precision_policy.dart';

void main() {
  const policy = DeepZoomPrecisionPolicy();

  group('DeepZoomPrecisionPolicy.shouldUseCpuFallback', () {
    test('returns false for mandelbrot at zoom 1e6', () {
      expect(
        policy.shouldUseCpuFallback(moduleId: 'mandelbrot', zoom: 1e6),
        isFalse,
      );
    });

    test('returns true for mandelbrot at zoom 1e15', () {
      expect(
        policy.shouldUseCpuFallback(moduleId: 'mandelbrot', zoom: 1e15),
        isTrue,
      );
    });

    test('uses default threshold for unknown module', () {
      // Default threshold is 1e7; zoom just below should be false.
      expect(
        policy.shouldUseCpuFallback(moduleId: 'unknown_fractal', zoom: 9.9e6),
        isFalse,
      );
      // At or above default threshold (1e7) should be true.
      expect(
        policy.shouldUseCpuFallback(moduleId: 'unknown_fractal', zoom: 1e7),
        isTrue,
      );
    });
  });

  group('DeepZoomPrecisionPolicy.shouldUseDoubleFloat', () {
    test('returns true for mandelbrot in df2 range', () {
      // df2 range: [5e6, 1e14)
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 5e6),
        isTrue,
      );
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 1e10),
        isTrue,
      );
    });

    test('returns false for non-mandelbrot modules', () {
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'julia', zoom: 1e10),
        isFalse,
      );
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'burning_ship', zoom: 1e10),
        isFalse,
      );
    });

    test('returns false below df2 lower threshold', () {
      // Below 5e6 the standard float32 shader is sufficient.
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 1e5),
        isFalse,
      );
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 4.9e6),
        isFalse,
      );
    });

    test('returns false at or above df2 upper threshold', () {
      // At 1e14 CPU fallback takes over; df2 should not be active.
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 1e14),
        isFalse,
      );
    });
  });

  group('DeepZoomPrecisionPolicy.scaledGpuIterations', () {
    test('returns base at zoom 1', () {
      expect(
        policy.scaledGpuIterations(baseIterations: 256, zoom: 1.0),
        equals(256),
      );
    });

    test('returns base at zoom below 1', () {
      expect(
        policy.scaledGpuIterations(baseIterations: 256, zoom: 0.5),
        equals(256),
      );
    });

    test('increases with zoom depth', () {
      final atZoom1 =
          policy.scaledGpuIterations(baseIterations: 256, zoom: 1.0);
      final atZoom1e6 =
          policy.scaledGpuIterations(baseIterations: 256, zoom: 1e6);
      expect(atZoom1e6, greaterThan(atZoom1));
    });

    test('clamps to gpuMaxIterations', () {
      // Very high base + very high zoom should be clamped.
      final result = policy.scaledGpuIterations(
        baseIterations: DeepZoomPrecisionPolicy.gpuMaxIterations,
        zoom: 1e30,
      );
      expect(result, equals(DeepZoomPrecisionPolicy.gpuMaxIterations));
    });

    test('clamps low base to minimum of 4', () {
      final result = policy.scaledGpuIterations(baseIterations: 1, zoom: 1.0);
      expect(result, equals(4));
    });
  });

  group('DeepZoomHysteresis', () {
    test('does not activate CPU until hysteresisFrames consecutive frames', () {
      final hysteresis = DeepZoomHysteresis(policy: policy);
      // mandelbrot CPU threshold is 1e14; zoom 2e14 is above it.
      const moduleId = 'mandelbrot';
      const highZoom = 2e14;
      final frames = policy.hysteresisFrames;

      // All frames before the last should still return false.
      for (var i = 0; i < frames - 1; i++) {
        expect(
          hysteresis.update(moduleId: moduleId, zoom: highZoom),
          isFalse,
          reason: 'frame $i should not activate CPU yet',
        );
      }

      // The hysteresisFrames-th frame should activate.
      expect(
        hysteresis.update(moduleId: moduleId, zoom: highZoom),
        isTrue,
      );
    });

    test('drops back to GPU immediately when zoom falls below threshold', () {
      final hysteresis = DeepZoomHysteresis(policy: policy);
      const moduleId = 'mandelbrot';
      const highZoom = 2e14;
      const lowZoom = 1.0;
      final frames = policy.hysteresisFrames;

      // Trigger CPU mode.
      for (var i = 0; i < frames; i++) {
        hysteresis.update(moduleId: moduleId, zoom: highZoom);
      }

      // A single below-threshold update drops back to GPU.
      expect(
        hysteresis.update(moduleId: moduleId, zoom: lowZoom),
        isFalse,
      );
    });

    test('does not carry above-threshold count across module changes', () {
      final hysteresis = DeepZoomHysteresis(policy: policy);

      expect(
        hysteresis.update(moduleId: 'julia', zoom: 2e9),
        isFalse,
        reason: 'first Julia deep-zoom frame should only prime hysteresis',
      );

      expect(
        hysteresis.update(moduleId: 'mandelbrot', zoom: 2e14),
        isFalse,
        reason: 'first Mandelbrot deep-zoom frame must not inherit Julia count',
      );

      expect(
        hysteresis.update(moduleId: 'mandelbrot', zoom: 2e14),
        isTrue,
        reason: 'second consecutive Mandelbrot deep-zoom frame activates CPU',
      );
    });

    test('reset clears state so hysteresis counter restarts', () {
      final hysteresis = DeepZoomHysteresis(policy: policy);
      const moduleId = 'mandelbrot';
      const highZoom = 2e14;
      final frames = policy.hysteresisFrames;

      // Build up to just before activation.
      for (var i = 0; i < frames - 1; i++) {
        hysteresis.update(moduleId: moduleId, zoom: highZoom);
      }

      hysteresis.reset();

      // After reset, the counter is zero; a single update should not activate.
      expect(
        hysteresis.update(moduleId: moduleId, zoom: highZoom),
        isFalse,
      );
    });
  });
}

import 'dart:typed_data';

class RenderFrameStats {
  final int centerR;
  final int centerG;
  final int centerB;
  final double nonBlackRatio;
  final bool centerNonBlack;
  final bool histogramSane;

  const RenderFrameStats({
    required this.centerR,
    required this.centerG,
    required this.centerB,
    required this.nonBlackRatio,
    required this.centerNonBlack,
    required this.histogramSane,
  });

  String summary(String backend) {
    return '[renderer] render_frame_stats backend=$backend center=$centerR,$centerG,$centerB non_black_ratio=${nonBlackRatio.toStringAsFixed(4)} histogram_sane=$histogramSane';
  }
}

RenderFrameStats validateRenderFrame({
  required Uint8List frame,
  required int width,
  required int height,
}) {
  int idx(int x, int y) => (y * width + x) * 4;

  final cx = (width / 2).floor();
  final cy = (height / 2).floor();
  final cIndex = idx(cx, cy);
  final centerR = frame[cIndex];
  final centerG = frame[cIndex + 1];
  final centerB = frame[cIndex + 2];

  final centerNonBlack = centerR > 8 || centerG > 8 || centerB > 8;

  int nonBlack = 0;
  final total = width * height;

  for (int i = 0; i + 3 < frame.length; i += 4) {
    if (frame[i] > 8 || frame[i + 1] > 8 || frame[i + 2] > 8) {
      nonBlack++;
    }
  }

  final nonBlackRatio = total == 0 ? 0.0 : nonBlack / total;
  final histogramSane = nonBlackRatio > 0.01;

  return RenderFrameStats(
    centerR: centerR,
    centerG: centerG,
    centerB: centerB,
    nonBlackRatio: nonBlackRatio,
    centerNonBlack: centerNonBlack,
    histogramSane: histogramSane,
  );
}

class RenderCheckResult {
  final int centerR;
  final int centerG;
  final int centerB;
  final double nonBlackRatio;
  final bool centerNonBlack;
  final bool histogramSane;
  final bool frameProgressed;
  final bool iterationDeltaVisible;

  const RenderCheckResult({
    required this.centerR,
    required this.centerG,
    required this.centerB,
    required this.nonBlackRatio,
    required this.centerNonBlack,
    required this.histogramSane,
    required this.frameProgressed,
    required this.iterationDeltaVisible,
  });

  bool get pass =>
      centerNonBlack &&
      histogramSane &&
      frameProgressed &&
      iterationDeltaVisible;

  String summary(String backend) {
    return '[renderer] render_check backend=$backend pass=$pass center=$centerR,$centerG,$centerB non_black_ratio=${nonBlackRatio.toStringAsFixed(4)} frame_progressed=$frameProgressed iter_delta=$iterationDeltaVisible';
  }
}

RenderCheckResult validateRenderPair({
  required Uint8List frameA,
  required Uint8List frameB,
  required int width,
  required int height,
}) {
  int idx(int x, int y) => (y * width + x) * 4;

  final cx = (width / 2).floor();
  final cy = (height / 2).floor();
  final cIndex = idx(cx, cy);
  final centerR = frameB[cIndex];
  final centerG = frameB[cIndex + 1];
  final centerB = frameB[cIndex + 2];

  final centerNonBlack = centerR > 8 || centerG > 8 || centerB > 8;

  int nonBlack = 0;
  int total = width * height;
  int different = 0;

  for (int i = 0; i + 3 < frameB.length; i += 4) {
    if (frameB[i] > 8 || frameB[i + 1] > 8 || frameB[i + 2] > 8) {
      nonBlack++;
    }

    final dr = (frameB[i] - frameA[i]).abs();
    final dg = (frameB[i + 1] - frameA[i + 1]).abs();
    final db = (frameB[i + 2] - frameA[i + 2]).abs();
    if (dr + dg + db > 12) different++;
  }

  final nonBlackRatio = total == 0 ? 0.0 : nonBlack / total;
  final histogramSane = nonBlackRatio > 0.01;
  final progressionRatio = total == 0 ? 0.0 : different / total;
  final frameProgressed = progressionRatio > 0.002;
  final iterationDeltaVisible = progressionRatio > 0.01;

  return RenderCheckResult(
    centerR: centerR,
    centerG: centerG,
    centerB: centerB,
    nonBlackRatio: nonBlackRatio,
    centerNonBlack: centerNonBlack,
    histogramSane: histogramSane,
    frameProgressed: frameProgressed,
    iterationDeltaVisible: iterationDeltaVisible,
  );
}

import 'dart:typed_data';

import 'package:flutter_fractals/features/renderer/render_validation.dart';
import 'package:flutter_test/flutter_test.dart';

/// Builds a Uint8List RGBA frame of [w]x[h] pixels, all zeroed (black).
Uint8List _blackFrame(int w, int h) => Uint8List(w * h * 4);

/// Pixel index for (x, y) in a [w]-wide RGBA frame.
int _px(int x, int y, int w) => (y * w + x) * 4;

void main() {
  group('validateRenderFrame', () {
    test('detects all-black frame', () {
      final frame = _blackFrame(4, 4);
      final stats = validateRenderFrame(frame: frame, width: 4, height: 4);

      expect(stats.centerR, 0);
      expect(stats.centerG, 0);
      expect(stats.centerB, 0);
      expect(stats.centerNonBlack, isFalse);
      expect(stats.nonBlackRatio, 0.0);
      expect(stats.histogramSane, isFalse);
    });

    test('detects non-black center pixel', () {
      final frame = _blackFrame(4, 4);
      // center of 4x4 is floor(2), floor(2) = (2,2)
      final idx = _px(2, 2, 4);
      frame[idx] = 100;
      frame[idx + 1] = 150;
      frame[idx + 2] = 200;

      final stats = validateRenderFrame(frame: frame, width: 4, height: 4);

      expect(stats.centerR, 100);
      expect(stats.centerG, 150);
      expect(stats.centerB, 200);
      expect(stats.centerNonBlack, isTrue);
    });

    test('calculates correct nonBlackRatio', () {
      // 8 pixels total; make exactly 4 non-black
      final frame = _blackFrame(4, 2);
      // pixels at (0,0),(1,0),(2,0),(3,0) — first row, r=20 > 8 threshold
      for (int col = 0; col < 4; col++) {
        frame[_px(col, 0, 4)] = 20;
      }
      final stats = validateRenderFrame(frame: frame, width: 4, height: 2);

      expect(stats.nonBlackRatio, closeTo(4 / 8, 1e-9));
    });

    test('histogramSane is false when ratio <= 0.01', () {
      // 100 pixels, only 1 non-black => ratio = 0.01 which is NOT > 0.01
      final frame = _blackFrame(10, 10);
      frame[0] = 20;
      final stats = validateRenderFrame(frame: frame, width: 10, height: 10);

      expect(stats.nonBlackRatio, closeTo(0.01, 1e-9));
      expect(stats.histogramSane, isFalse);
    });

    test('histogramSane is true when ratio > 0.01', () {
      // 100 pixels, 2 non-black => ratio = 0.02 > 0.01
      final frame = _blackFrame(10, 10);
      frame[0] = 20;
      frame[4] = 20; // next pixel (x=1,y=0)
      final stats = validateRenderFrame(frame: frame, width: 10, height: 10);

      expect(stats.nonBlackRatio, closeTo(0.02, 1e-9));
      expect(stats.histogramSane, isTrue);
    });

    test('summary includes backend name', () {
      final frame = _blackFrame(4, 4);
      final stats = validateRenderFrame(frame: frame, width: 4, height: 4);
      final summary = stats.summary('gpu');

      expect(summary, contains('backend=gpu'));
      expect(summary, contains('[renderer]'));
      expect(summary, contains('non_black_ratio='));
      expect(summary, contains('histogram_sane='));
    });

    test('boundary: threshold pixel value of 8 is still counted as black', () {
      final frame = _blackFrame(4, 4);
      // Set center pixel RGB all to exactly 8 — threshold is > 8, so this is black
      final idx = _px(2, 2, 4);
      frame[idx] = 8;
      frame[idx + 1] = 8;
      frame[idx + 2] = 8;

      final stats = validateRenderFrame(frame: frame, width: 4, height: 4);
      expect(stats.centerNonBlack, isFalse);
    });

    test('boundary: pixel value of 9 is counted as non-black', () {
      final frame = _blackFrame(4, 4);
      final idx = _px(2, 2, 4);
      frame[idx] = 9;

      final stats = validateRenderFrame(frame: frame, width: 4, height: 4);
      expect(stats.centerNonBlack, isTrue);
    });
  });

  group('validateRenderPair', () {
    test('detects frame progression when enough pixels differ', () {
      final frameA = _blackFrame(4, 4);
      final frameB = _blackFrame(4, 4);

      // Make every pixel differ significantly (dr+dg+db > 12)
      for (int i = 0; i < frameB.length; i += 4) {
        frameB[i] = 50;
        frameB[i + 1] = 50;
        frameB[i + 2] = 50;
      }

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 4,
        height: 4,
      );

      expect(result.frameProgressed, isTrue);
      expect(result.iterationDeltaVisible, isTrue);
    });

    test('frameProgressed is false when frames are identical', () {
      final frameA = _blackFrame(4, 4);
      final frameB = Uint8List.fromList(frameA);

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 4,
        height: 4,
      );

      expect(result.frameProgressed, isFalse);
      expect(result.iterationDeltaVisible, isFalse);
    });

    test('iterationDeltaVisible requires > 1% different pixels', () {
      // 100 pixels total; need > 1 different pixel for iterationDeltaVisible
      // Exactly 1 different pixel => 1% which is NOT > 0.01
      final frameA = _blackFrame(10, 10);
      final frameB = Uint8List.fromList(frameA);
      frameB[0] = 100;
      frameB[1] = 100;
      frameB[2] = 100;

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 10,
        height: 10,
      );

      // progressionRatio = 1/100 = 0.01; frameProgressed needs > 0.002 (true)
      expect(result.frameProgressed, isTrue);
      // iterationDeltaVisible needs > 0.01 (false — exactly 0.01)
      expect(result.iterationDeltaVisible, isFalse);
    });

    test('pass is true only when all checks pass', () {
      // Build a 10x10 frame where enough pixels are non-black and different
      final frameA = _blackFrame(10, 10);
      final frameB = _blackFrame(10, 10);

      // Fill all pixels in frameB with colour that exceeds all thresholds
      for (int i = 0; i < frameB.length; i += 4) {
        frameB[i] = 80;
        frameB[i + 1] = 80;
        frameB[i + 2] = 80;
        frameB[i + 3] = 255;
      }

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 10,
        height: 10,
      );

      expect(result.centerNonBlack, isTrue);
      expect(result.histogramSane, isTrue);
      expect(result.frameProgressed, isTrue);
      expect(result.iterationDeltaVisible, isTrue);
      expect(result.pass, isTrue);
    });

    test('pass is false when centerNonBlack is false', () {
      // Non-zero progression but center stays black
      final frameA = _blackFrame(10, 10);
      final frameB = _blackFrame(10, 10);

      // Colour many pixels except the center (5,5)
      for (int row = 0; row < 10; row++) {
        for (int col = 0; col < 10; col++) {
          if (row == 5 && col == 5) continue;
          final i = _px(col, row, 10);
          frameB[i] = 80;
          frameB[i + 1] = 80;
          frameB[i + 2] = 80;
        }
      }

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 10,
        height: 10,
      );

      expect(result.centerNonBlack, isFalse);
      expect(result.pass, isFalse);
    });

    test('handles all-identical frames — no progression', () {
